1	package main
2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"path/filepath"
8		"slices"
9		"sort"
10		"strings"
11	
12		"github.com/pdfcpu/pdfcpu/pkg/api"
13	)
14	
15	// mergePDFs interleaves pages from pathA and pathB into outPath.
16	// If firstPageInA is true, file A contributes the odd-numbered output pages (1, 3, 5, …);
17	// otherwise file B does. If reverseB is true, file B's pages are reversed before interleaving,
18	// which is the typical case when the paper stack was flipped between scans.
19	// If the page counts differ, the extra pages from the longer file are
20	// appended in order after the interleaved section.
21	func mergePDFs(pathA, pathB, outPath string, firstPageInA, reverseB bool, skipA, skipB []int, rotationsA, rotationsB map[int]int) error {
22		tmpDir, err := os.MkdirTemp("", "psp-merge-*")
23		if err != nil {
24			return err
25		}
26		defer os.RemoveAll(tmpDir)
27	
28		dirA := filepath.Join(tmpDir, "a")
29		dirB := filepath.Join(tmpDir, "b")
30		for _, d := range []string{dirA, dirB} {
31			if err := os.MkdirAll(d, 0o755); err != nil {
32				return err
33			}
34		}
35	
36		if err := api.SplitFile(pathA, dirA, 1, nil); err != nil {
37			return fmt.Errorf("splitting file A: %w", err)
38		}
39		if err := api.SplitFile(pathB, dirB, 1, nil); err != nil {
40			return fmt.Errorf("splitting file B: %w", err)
41		}
42	
43		pagesA, err := sortedPDFsInDir(dirA)
44		if err != nil {
45			return fmt.Errorf("listing file A pages: %w", err)
46		}
47		pagesB, err := sortedPDFsInDir(dirB)
48		if err != nil {
49			return fmt.Errorf("listing file B pages: %w", err)
50		}
51	
52		pagesA = filterSkipped(pagesA, skipA)
53		pagesB = filterSkipped(pagesB, skipB)
54		if reverseB {
55			slices.Reverse(pagesB)
56		}
57	
58		if err := applyRotations(pagesA, rotationsA); err != nil {
59			return fmt.Errorf("rotating file A pages: %w", err)
60		}
61		if err := applyRotations(pagesB, rotationsB); err != nil {
62			return fmt.Errorf("rotating file B pages: %w", err)
63		}
64	
65		if firstPageInA {
66			return api.MergeCreateFile(interleave(pagesA, pagesB), outPath, false, nil)
67		}
68		return api.MergeCreateFile(interleave(pagesB, pagesA), outPath, false, nil)
69	}
70	
71	func filterSkipped(pages []string, skip []int) []string {
72		if len(skip) == 0 {
73			return pages
74		}
75		skipSet := make(map[int]bool, len(skip))
76		for _, p := range skip {
77			skipSet[p] = true
78		}
79		out := make([]string, 0, len(pages))
80		for i, p := range pages {
81			if !skipSet[i+1] {
82				out = append(out, p)
83			}
84		}
85		return out
86	}
87	
88	// applyRotations rotates individual single-page PDF files in-place according to
89	// the rotations map (1-indexed page number → clockwise degrees: 90, 180, 270).
90	// The page number is derived from the pdfcpu split filename.
91	func applyRotations(pages []string, rotations map[int]int) error {
92		for _, p := range pages {
93			origPage := pdfFromPage(filepath.Base(p))
94			rot, ok := rotations[origPage]
95			if !ok || rot == 0 {
96				continue
97			}
98			tmp := p + ".rot.pdf"
99			if err := api.RotateFile(p, tmp, rot, nil, nil); err != nil {
100				return fmt.Errorf("page %d: %w", origPage, err)
101			}
102			if err := os.Rename(tmp, p); err != nil {
103				return err
104			}
105		}
106		return nil
107	}
108	
109	// splitPDF splits the PDF at inPath at the given page boundaries and writes
110	// each segment to outDir, returning the output file paths in order.
111	// splitAfter contains 1-indexed page numbers after which a new file begins.
112	// E.g. splitAfter=[2,4] on a 6-page PDF produces three files: pages 1-2, 3-4, 5-6.
113	// rotations maps 1-indexed original page numbers to clockwise degrees (90, 180, 270).
114	func splitPDF(inPath string, splitAfter []int, rotations map[int]int, outDir string) ([]string, error) {
115		src := inPath
116		if len(rotations) > 0 {
117			// Rotate before splitting so SplitByPageNrFile operates on the final pages.
118			// Use a subdirectory so sortedPDFsInDir(outDir) doesn't pick up this file.
119			preDir := filepath.Join(outDir, "pre")
120			if err := os.MkdirAll(preDir, 0o755); err != nil {
121				return nil, err
122			}
123			rotated := filepath.Join(preDir, "rotated.pdf")
124			if err := applyRotationsToFile(inPath, rotated, rotations); err != nil {
125				return nil, err
126			}
127			src = rotated
128		}
129	
130		if len(splitAfter) == 0 {
131			outPath := filepath.Join(outDir, "output.pdf")
132			if err := copyFile(src, outPath); err != nil {
133				return nil, err
134			}
135			return []string{outPath}, nil
136		}
137	
138		// SplitByPageNrFile expects the first page of each new segment.
139		pageNrs := make([]int, len(splitAfter))
140		for i, p := range splitAfter {
141			pageNrs[i] = p + 1
142		}
143		if err := api.SplitByPageNrFile(src, outDir, pageNrs, nil); err != nil {
144			return nil, fmt.Errorf("splitting PDF: %w", err)
145		}
146		return sortedPDFsInDir(outDir)
147	}
148	
149	// applyRotationsToFile writes a copy of inPath to outPath with the specified
150	// page rotations applied. It chains one api.RotateFile call per distinct degree.
151	func applyRotationsToFile(inPath, outPath string, rotations map[int]int) error {
152		byDeg := make(map[int][]string)
153		for page, deg := range rotations {
154			byDeg[deg] = append(byDeg[deg], fmt.Sprintf("%d", page))
155		}
156	
157		src := inPath
158		i := 0
159		for deg, pages := range byDeg {
160			dst := outPath
161			if i < len(byDeg)-1 {
162				dst = fmt.Sprintf("%s.%d.tmp", outPath, i)
163			}
164			if err := api.RotateFile(src, dst, deg, pages, nil); err != nil {
165				return fmt.Errorf("rotate %d°: %w", deg, err)
166			}
167			if src != inPath {
168				os.Remove(src)
169			}
170			src = dst
171			i++
172		}
173		return nil
174	}
175	
176	// pdfPageCount returns the number of pages in the PDF at path.
177	func pdfPageCount(path string) (int, error) {
178		return api.PageCountFile(path)
179	}
180	
181	// sortedPDFsInDir lists PDF files in dir sorted numerically by the first page
182	// number encoded in pdfcpu's output filenames (e.g. "doc_3-5.pdf" → 3).
183	func sortedPDFsInDir(dir string) ([]string, error) {
184		entries, err := os.ReadDir(dir)
185		if err != nil {
186			return nil, err
187		}
188		type item struct {
189			path     string
190			fromPage int
191		}
192		var files []item
193		for _, e := range entries {
194			if e.IsDir() || !strings.HasSuffix(strings.ToLower(e.Name()), ".pdf") {
195				continue
196			}
197			files = append(files, item{
198				path:     filepath.Join(dir, e.Name()),
199				fromPage: pdfFromPage(e.Name()),
200			})
201		}
202		sort.Slice(files, func(i, j int) bool { return files[i].fromPage < files[j].fromPage })
203		result := make([]string, len(files))
204		for i, f := range files {
205			result[i] = f.path
206		}
207		return result, nil
208	}
209	
210	// interleave merges two slices by alternating elements: a[0], b[0], a[1], b[1], ...
211	// If the slices have different lengths, the remaining elements of the longer
212	// slice are appended in order after the interleaved section.
213	func interleave[T any](a, b []T) []T {
214		n := min(len(a), len(b))
215		out := make([]T, 0, len(a)+len(b))
216		for i := range n {
217			out = append(out, a[i], b[i])
218		}
219		out = append(out, a[n:]...)
220		out = append(out, b[n:]...)
221		return out
222	}
223	
224	func copyFile(src, dst string) error {
225		in, err := os.Open(src)
226		if err != nil {
227			return err
228		}
229		defer in.Close()
230		out, err := os.Create(dst)
231		if err != nil {
232			return err
233		}
234		defer out.Close()
235		_, err = io.Copy(out, in)
236		return err
237	}
238	
239	// pdfFromPage extracts the first page number from a pdfcpu split filename
240	// such as "doc_1.pdf" or "doc_3-5.pdf".
241	func pdfFromPage(name string) int {
242		name = strings.TrimSuffix(name, ".pdf")
243		parts := strings.Split(name, "_")
244		if len(parts) == 0 {
245			return 0
246		}
247		rangeStr := parts[len(parts)-1]
248		n := 0
249		fmt.Sscanf(strings.SplitN(rangeStr, "-", 2)[0], "%d", &n)
250		return n
251	}
