1	package main
2	
3	import (
4		"context"
5		"encoding/base64"
6		"fmt"
7		"os"
8		"os/exec"
9		"path/filepath"
10		"strconv"
11		"strings"
12	
13		"github.com/wailsapp/wails/v2/pkg/runtime"
14	)
15	
16	// App struct
17	type App struct {
18		ctx context.Context
19	}
20	
21	// NewApp creates a new App application struct
22	func NewApp() *App {
23		return &App{}
24	}
25	
26	// startup is called when the app starts. The context is saved
27	// so we can call the runtime methods
28	func (a *App) startup(ctx context.Context) {
29		a.ctx = ctx
30	}
31	
32	// OpenPDF shows a file-open dialog filtered to PDFs and returns the selected path.
33	// Returns an empty string if the user cancels.
34	func (a *App) OpenPDF() (string, error) {
35		path, err := runtime.OpenFileDialog(a.ctx, runtime.OpenDialogOptions{
36			Title: "Open PDF",
37			Filters: []runtime.FileFilter{
38				{DisplayName: "PDF Files (*.pdf)", Pattern: "*.pdf"},
39			},
40		})
41		return path, err
42	}
43	
44	// PageCount returns the number of pages in the PDF at path.
45	func (a *App) PageCount(path string) (int, error) {
46		return pdfPageCount(path)
47	}
48	
49	// RenderPage renders a single page of the PDF at path as a PNG and returns it
50	// base64-encoded. widthPx controls the output width; height is scaled proportionally.
51	func (a *App) RenderPage(path string, pageNum int, widthPx int) (string, error) {
52		tmpDir, err := os.MkdirTemp("", "psp-render-*")
53		if err != nil {
54			return "", err
55		}
56		defer os.RemoveAll(tmpDir)
57	
58		outPrefix := filepath.Join(tmpDir, "page")
59		page := strconv.Itoa(pageNum)
60	
61		out, err := exec.Command(
62			"pdftoppm",
63			"-f", page,
64			"-l", page,
65			"-singlefile",
66			"-png",
67			"-scale-to-x", strconv.Itoa(widthPx),
68			"-scale-to-y", "-1",
69			path,
70			outPrefix,
71		).CombinedOutput()
72		if err != nil {
73			return "", fmt.Errorf("pdftoppm: %w\n%s", err, out)
74		}
75	
76		data, err := os.ReadFile(outPrefix + ".png")
77		if err != nil {
78			return "", err
79		}
80		return base64.StdEncoding.EncodeToString(data), nil
81	}
82	
83	// SavePDF shows a save-file dialog filtered to PDFs and returns the chosen path.
84	// Returns an empty string if the user cancels.
85	func (a *App) SavePDF() (string, error) {
86		path, err := runtime.SaveFileDialog(a.ctx, runtime.SaveDialogOptions{
87			Title:           "Save Merged PDF",
88			DefaultFilename: "merged.pdf",
89			Filters: []runtime.FileFilter{
90				{DisplayName: "PDF Files (*.pdf)", Pattern: "*.pdf"},
91			},
92		})
93		if err != nil || path == "" {
94			return path, err
95		}
96		if !strings.HasSuffix(strings.ToLower(path), ".pdf") {
97			path += ".pdf"
98		}
99		return path, nil
100	}
101	
102	// OpenFile opens the file at path with the system default application.
103	func (a *App) OpenFile(path string) error {
104		return exec.Command("open", path).Run()
105	}
106	
107	// MergePDFs interleaves pages from pathA and pathB and writes the result to outPath.
108	func (a *App) MergePDFs(pathA, pathB, outPath string, firstPageInA, reverseB bool, skipA, skipB []int, rotationsA, rotationsB map[int]int) error {
109		return mergePDFs(pathA, pathB, outPath, firstPageInA, reverseB, skipA, skipB, rotationsA, rotationsB)
110	}
111	
112	// PickFolder shows a folder-select dialog and returns the chosen path.
113	// Returns an empty string if the user cancels.
114	func (a *App) PickFolder() (string, error) {
115		return runtime.OpenDirectoryDialog(a.ctx, runtime.OpenDialogOptions{
116			Title: "Choose Output Folder",
117		})
118	}
119	
120	// OutputFileSpec describes one output file for ExportSplit.
121	type OutputFileSpec struct {
122		FirstPage int    `json:"firstPage"` // 1-indexed; first entry must be 1
123		Name      string `json:"name"`      // filename without extension; falls back to "output-N" if empty
124		OutDir    string `json:"outDir"`    // destination directory
125	}
126	
127	// ExportSplit splits the PDF at inPath according to files (sorted by FirstPage)
128	// and writes each segment to its OutDir using its Name.
129	// rotations maps 1-indexed page numbers to clockwise degrees (90, 180, 270).
130	func (a *App) ExportSplit(inPath string, files []OutputFileSpec, rotations map[int]int) error {
131		tmpDir, err := os.MkdirTemp("", "psp-split-*")
132		if err != nil {
133			return err
134		}
135		defer os.RemoveAll(tmpDir)
136	
137		splitAfter := make([]int, 0, len(files)-1)
138		for _, f := range files {
139			if f.FirstPage > 1 {
140				splitAfter = append(splitAfter, f.FirstPage-1)
141			}
142		}
143	
144		paths, err := splitPDF(inPath, splitAfter, rotations, tmpDir)
145		if err != nil {
146			return err
147		}
148	
149		for i, src := range paths {
150			name := strings.TrimSpace(files[i].Name)
151			if name == "" {
152				name = fmt.Sprintf("output-%d", i+1)
153			}
154			if !strings.HasSuffix(strings.ToLower(name), ".pdf") {
155				name += ".pdf"
156			}
