367		for i, want := range []int{2, 2, 2} {
368			if got, err := pdfPageCount(parts[i]); err != nil {
369				t.Fatalf("part %d: %v", i, err)
370			} else if got != want {
371				t.Errorf("part %d: got %d pages, want %d", i, got, want)
372			}
373		}
374	
375		for i, labels := range [][]string{{"P1", "P2"}, {"P3", "P4"}, {"P5", "P6"}} {
376			data, err := os.ReadFile(parts[i])
377			if err != nil {
378				t.Fatal(err)
379			}
380			assertOrder(t, data, labels)
381		}
382	}
383	
384	func TestSplitPDFSingleOutput(t *testing.T) {
385		tmp := t.TempDir()
386		in := filepath.Join(tmp, "input.pdf")
387		outDir := filepath.Join(tmp, "out")
388		if err := os.MkdirAll(outDir, 0o755); err != nil {
389			t.Fatal(err)
390		}
391	
392		writePDF(t, in, []string{"P1", "P2", "P3", "P4"})
393	
394		parts, err := splitPDF(in, nil, nil, outDir)
395		if err != nil {
396			t.Fatal(err)
397		}
398	
399		if len(parts) != 1 {
400			t.Fatalf("got %d parts, want 1", len(parts))
401		}
402	
403		if got, err := pdfPageCount(parts[0]); err != nil {
404			t.Fatal(err)
405		} else if got != 4 {
406			t.Errorf("got %d pages, want 4", got)
407		}
408	}
